import { useState } from "react";
import { motion } from "framer-motion";
import { Clock } from "lucide-react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import FreelanceExpandedContent, { FREELANCE_EXPANDED_FAQS } from "@/components/FreelanceExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmtCurrency(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 2 });
}

const FAQS = [
  { q: "How do I calculate my freelance hourly rate?", a: "Add your monthly income goal to your monthly expenses, multiply by 12 to get your annual need, then divide by your annual billable hours (weekly hours  x  52). This gives your minimum viable hourly rate." },
  { q: "Should I include taxes in my freelance rate?", a: "Yes. Freelancers typically owe 25-35% in self-employment and income taxes. Add an estimated tax buffer to your monthly expenses field to ensure your rate accounts for tax obligations." },
  { q: "What is a good hourly rate for a freelancer?", a: "A good rate depends on your skill level, niche, and market. Entry-level freelancers typically charge $25-$50/hr, mid-level $50-$100/hr, and experienced specialists $100-$300+/hr." },
  { q: "How many billable hours should I plan for per week?", a: "Realistically, only 60-70% of working hours are billable. If you work 40 hours per week, plan for 25-30 billable hours. Factor this into your weekly hours input for accuracy." },
  { q: "Should I charge hourly or per project?", a: "Both have merits. Hourly works well for ongoing or undefined-scope work; project-based pricing rewards efficiency. Use this calculator to find your minimum hourly rate, then price projects accordingly." },
  { q: "How do I raise my freelance rate without losing clients?", a: "Give existing clients 30-60 days' notice, frame it as a 'rate review,' and provide a business case (increased demand, specialized skills, market rates). New clients should always see your new rate immediately." },
  { q: "What is the 3x rule for freelance rates?", a: "The 3x rule states your freelance rate should be 3x the equivalent employee hourly rate to account for: self-employment tax (~15%), health insurance, unpaid time (vacations, admin), and non-billable hours. If an employee earns $30/hr, a freelancer with the same skills should charge $90/hr." },
  { q: "How do I calculate my effective hourly rate if I charge per project?", a: "Track your total hours spent on a project (including emails, revisions, meetings). Divide the project fee by total hours. If a $1,000 project took 15 hours, your effective rate is $66.67/hr. Compare this to your target rate to assess pricing accuracy." },
];

const EXPANDED_FAQS = FREELANCE_EXPANDED_FAQS.hourly;

export default function FreelanceCalculator() {
  useCurrencyVersion();
  const [monthlyGoal, setMonthlyGoal] = useState(5000);
  const [weeklyHours, setWeeklyHours] = useState(30);
  const [expenses, setExpenses] = useState(500);

  const annualNeed = (monthlyGoal + expenses) * 12;
  const annualHours = weeklyHours * 52;
  const hourlyRate = annualHours > 0 ? annualNeed / annualHours : 0;
  const dailyRate = hourlyRate * 8;
  const weeklyRate = hourlyRate * weeklyHours;

  const rateRows = [20, 25, 30, 35, 40, 45, 50].map(hrs => ({
    hrs,
    rate: annualHours > 0 ? annualNeed / (hrs * 52) : 0,
  }));

  return (
    <>
      <SEOHead
        title="Free Freelance Hourly Rate Calculator Online - Instant Results | CalcHive"
        description="Use our 100% free freelance hourly rate calculator online. Instantly calculate your ideal hourly rate based on income goals, expenses and work hours. No signup required. Free for everyone."
        canonical="/freelance-hourly-rate-calculator"
        keywords="free freelance hourly rate calculator, free online hourly rate calculator, calculate freelance rate free, freelance pricing calculator free, no signup free calculator"
        category="Freelance"
        faqs={EXPANDED_FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="inline-flex items-center gap-1.5 text-xs font-semibold uppercase tracking-widest text-primary bg-accent px-3 py-1 rounded-full mb-4">
            <Clock className="w-3.5 h-3.5" /> Freelance
          </span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Freelance Hourly Rate Calculator</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free freelance hourly rate calculator to find the minimum rate you should charge to hit your income goal, cover expenses, and stay profitable. This free online hourly rate calculator updates instantly as you adjust your work hours and costs.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8" aria-label="Freelance hourly rate calculator">
          <div className="space-y-6 mb-8">
            <SliderInput id="monthly-goal" label="Monthly Income Goal" value={monthlyGoal} min={500} max={30000} step={100} onChange={setMonthlyGoal} format={fmtCurrency} testId="input-monthly-goal" />
            <SliderInput id="weekly-hours" label="Weekly Billable Hours" value={weeklyHours} min={1} max={80} step={1} onChange={setWeeklyHours} testId="input-weekly-hours" helpText="hours/week" />
            <SliderInput id="expenses" label="Monthly Business Expenses" value={expenses} min={0} max={10000} step={100} onChange={setExpenses} format={fmtCurrency} testId="input-expenses" />
          </div>
          <motion.div key={`${monthlyGoal}-${weeklyHours}-${expenses}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-primary to-indigo-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-primary-foreground/70 mb-1">Suggested Hourly Rate</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-hourly-rate">{fmtCurrency(hourlyRate)}</p>
              <p className="text-primary-foreground/70 text-sm mt-1">per hour</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Daily Rate", value: fmtCurrency(dailyRate), testId: "result-daily-rate" },
                { label: "Weekly Rate", value: fmtCurrency(weeklyRate), testId: "result-weekly-rate" },
                { label: "Needed / Year", value: fmtCurrency(annualNeed), testId: "result-annual-need" },
              ].map(({ label, value, testId }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground" data-testid={testId}>{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Calculate Your Freelance Hourly Rate for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Your minimum viable hourly rate is the rate below which you cannot cover your income needs and expenses. Use this freelance pricing calculator free to calculate freelance rate free from your annual financial requirement divided by your total billable hours per year.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Annual Need = (Monthly Goal + Monthly Expenses)  x  12</p>
            <p>Annual Billable Hours = Weekly Hours  x  52</p>
            <p>Hourly Rate = Annual Need  x  Annual Billable Hours</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find Your Perfect Freelance Rate</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Weekly Hours", "Required Hourly Rate", "Daily Rate (8 hrs)", "Annual Hours"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {rateRows.map(({ hrs, rate }) => (
                  <tr key={hrs} className={`hover:bg-muted/30 ${hrs === weeklyHours ? "bg-primary/5 font-medium" : ""}`}>
                    <td className="py-2.5 px-4 font-semibold text-foreground">{hrs} hrs/week {hrs === weeklyHours ? "(current)" : ""}</td>
                    <td className="py-2.5 px-4 text-primary font-semibold">{fmtCurrency(rate)}/hr</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{fmtCurrency(rate * 8)}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{(hrs * 52).toLocaleString()} hrs</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Why Every Freelancer Needs This Free Tool</h2>
          <p className="text-muted-foreground leading-relaxed">A no signup free calculator helps you check rates before quoting clients, compare your billable hours, and avoid underpricing work. Use these benchmarks as context after the calculator shows your personal minimum rate.</p>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Field", "Entry Level", "Mid Level", "Senior / Expert"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Web Development", "$25-$50/hr", "$75-$125/hr", "$150-$300/hr"],
                  ["Graphic Design", "$20-$40/hr", "$50-$90/hr", "$100-$200/hr"],
                  ["Copywriting", "$20-$40/hr", "$60-$100/hr", "$125-$250/hr"],
                  ["Video Editing", "$20-$35/hr", "$50-$80/hr", "$100-$200/hr"],
                  ["Social Media Mgmt", "$15-$25/hr", "$40-$70/hr", "$80-$150/hr"],
                  ["Business Consulting", "$75-$100/hr", "$100-$175/hr", "$200-$500/hr"],
                  ["Data Analysis", "$30-$50/hr", "$75-$125/hr", "$150-$300/hr"],
                ].map(([field, ...rates]) => (
                  <tr key={field} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{field}</td>
                    {rates.map((r, i) => <td key={i} className="py-2.5 px-4 text-muted-foreground">{r}</td>)}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <FreelanceExpandedContent kind="hourly" />

        <section aria-labelledby="faq-heading" className="mb-8">
          <h2 id="faq-heading" className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h2>
          <div className="space-y-3">{EXPANDED_FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/freelance-hourly-rate-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


